#include<bits/stdc++.h>
using namespace std;
int dp[3831][3830][2],a[3831];
int main()
{
    int n,b,ans;
    scanf("%d%d",&n,&b);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    memset(dp,-0x3f,sizeof(dp));
    dp[1][1][1]=dp[1][0][0]=0;
    for(int i=2;i<=n;i++)
    {
        for(int j=0;j<=b;j++)
        {
            dp[i][j][0]=max(dp[i-1][j][0],dp[i-1][j][1]);
            dp[i][j][1]=max(dp[i-1][j-1][0],dp[i-1][j-1][1]+a[i]);
        }
    }
    ans=max(dp[n][b][0],dp[n][b][1]);
    memset(dp,-0x3f,sizeof(dp));
    dp[1][1][1]=a[1];
    dp[1][0][0]=0;
    for(int i=2;i<=n;i++)
    {
        for(int j=0;j<=b;j++)
        {
            dp[i][j][0]=max(dp[i-1][j][0],dp[i-1][j][1]);
            dp[i][j][1]=max(dp[i-1][j-1][0],dp[i-1][j-1][1]+a[i]);
        }
    }
    printf("%d",max(ans,dp[n][b][1]));
    return 0;
}
